def seed(db: Session):
    existing = db.query(Question).count()
    if existing > 0:
        print(f"  Questions: already {existing}, skipping")
        return
    for data in QUESTIONS_DATA:
        db.add(Question(**data, app_source="spektr"))
    db.commit()
    print(f"  Questions: {len(QUESTIONS_DATA)} seeded")
